1	const PROCESSING_FEE = 5;
2	const FIRST_CONTRACT_INSURANCE_RATE = 0.1;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
6	const COMPONENT_BASE_PREMIUM = 25;
7	const COMPONENT_INSURANCE_VALUE = 250;
8	const BUILDING_BLOCK_SIZE = 3;
9	const BUILDING_BLOCK_BASE_PREMIUM = 60;
10	const CURSE_SURCHARGE_RATE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const DEDUCTIBLE_PER_DAMAGE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
19	type Customer = { yearsWithMHPCO: number };
20	type Damage = { itemType: string; amount: number };
21	type Incident = { cause: string; damages: Damage[] };
22	type QuoteStep = { op: "quote"; items: Item[] };
23	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
24	type Step = QuoteStep | ClaimStep;
25	type Scenario = { customer: Customer; steps: Step[] };
26	
27	type QuoteResult = { premium: number };
28	type ClaimResult = { payout: number; remainingCap: number };
29	type StepResult = QuoteResult | ClaimResult;
30	
31	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	};
37	
38	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
39	  sword: 1000,
40	  amulet: 600,
41	  staff: 800,
42	  potion: 400,
43	};
44	
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const isComponent = (type: string) => COMPONENT_TYPES.has(type);
48	
49	const isKnownItemType = (type: string): boolean =>
50	  type in MAIN_ITEM_BASE_PREMIUM || COMPONENT_TYPES.has(type);
51	
52	const validateItems = (items: Item[]): void => {
53	  for (const item of items) {
54	    if (!isKnownItemType(item.type)) {
55	      throw new Error(`Unknown item type: ${item.type}`);
56	    }
57	  }
58	};
59	
60	const itemInsuranceValue = (item: Item): number =>
61	  isComponent(item.type) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];
62	
63	const componentsGroupBase = (count: number): number => {
64	  if (count === BUILDING_BLOCK_SIZE) return BUILDING_BLOCK_BASE_PREMIUM;
65	  return count * COMPONENT_BASE_PREMIUM;
66	};
67	
68	const itemBasePremium = (item: Item): number => {
69	  if (isComponent(item.type)) return COMPONENT_BASE_PREMIUM;
70	  return MAIN_ITEM_BASE_PREMIUM[item.type];
71	};
72	
73	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
74	
75	const itemSurcharges = (item: Item): number => {
76	  if (isComponent(item.type)) return 0;
77	  const base = itemBasePremium(item);
78	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
79	  const highEnchantment =
80	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
81	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
82	      : 0;
83	  return curse + highEnchantment;
84	};
85	
86	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
87	
88	// MHPCO-favor rounding: premiums round up, payouts round down — both in MHPCO's favor.
89	const roundPremiumInMHPCOFavor = (amount: number): number => Math.ceil(amount);
90	const roundPayoutInMHPCOFavor = (amount: number): number => Math.floor(amount);
91	
92	const countBy = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> =>
93	  values.reduce((counts, value) => {
94	    const key = keyOf(value);
95	    counts.set(key, (counts.get(key) ?? 0) + 1);
96	    return counts;
97	  }, new Map<string, number>());
98	
99	const countItemsByType = (items: Item[]): Map<string, number> =>
100	  countBy(items, (item) => item.type);
101	
102	const countDamagesByItemType = (damages: Damage[]): Map<string, number> =>
103	  countBy(damages, (damage) => damage.itemType);
104	
105	const policyBaseSum = (items: Item[]): number => {
106	  const mainItems = items.filter((i) => !isComponent(i.type));
107	  const components = items.filter((i) => isComponent(i.type));
108	  const mainSum = sum(mainItems.map(itemBasePremium));
109	  const componentsSum = sum(
110	    Array.from(countItemsByType(components).values(), componentsGroupBase)
111	  );
112	  return mainSum + componentsSum;
113	};
114	
115	const policyItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
116	
117	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
118	  const baseSum = policyBaseSum(items);
119	  const surcharges = policyItemSurcharges(items);
120	  const firstContractInsurance = baseSum * FIRST_CONTRACT_INSURANCE_RATE;
121	  const loyaltyDiscount =
122	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
123	  const followUpDiscount = isFollowUp ? baseSum * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
124	  return roundPremiumInMHPCOFavor(
125	    baseSum + surcharges + firstContractInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE
126	  );
127	};
128	
129	type Policy = { items: Item[]; cap: number };
130	
131	const createPolicy = (items: Item[]): Policy => {
132	  const insuranceSum = sum(items.map(itemInsuranceValue));
133	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
134	};
135	
136	const qualifiesForHighEnchantmentClaim = (item: Item | undefined): boolean =>
137	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
138	
139	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
140	  qualifiesForHighEnchantmentClaim(item)
141	    ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
142	    : damage.amount;
143	
144	const damagePayout = (damage: Damage, items: Item[]): number => {
145	  const damagedItem = items.find((i) => i.type === damage.itemType);
146	  const reimbursable = reimbursableAmount(damage, damagedItem);
147	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
148	};
149	
150	const validateDamageCountsWithinPolicy = (policy: Policy, damages: Damage[]): void => {
151	  const policyCounts = countItemsByType(policy.items);
152	  const damageCounts = countDamagesByItemType(damages);
153	  for (const [itemType, damageCount] of damageCounts) {
154	    const policyCount = policyCounts.get(itemType) ?? 0;
155	    if (damageCount > policyCount) {
156	      throw new Error(
157	        `Claim rejected: ${damageCount} damages for ${itemType} but policy covers only ${policyCount}`,
158	      );
159	    }
160	  }
161	};
162	
163	const validateDamageAmountsNonNegative = (damages: Damage[]): void => {
164	  for (const damage of damages) {
165	    if (damage.amount < 0) {
166	      throw new Error(`Invalid damage amount: ${damage.amount}`);
167	    }
168	  }
169	};
170	
171	const validateClaim = (policy: Policy, damages: Damage[]): void => {
172	  validateDamageAmountsNonNegative(damages);
173	  validateDamageCountsWithinPolicy(policy, damages);
174	};
175	
176	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
177	  validateClaim(policy, incident.damages);
178	  const rawPayout = sum(incident.damages.map((d) => damagePayout(d, policy.items)));
179	  const payout = roundPayoutInMHPCOFavor(Math.min(rawPayout, policy.cap));
180	  policy.cap -= payout;
181	  return { payout, remainingCap: policy.cap };
182	};
183	
184	const handleQuote = (
185	  step: QuoteStep,
186	  customer: Customer,
187	  policies: Policy[],
188	): QuoteResult => {
189	  validateItems(step.items);
190	  const isFollowUp = policies.length > 0;
191	  policies.push(createPolicy(step.items));
192	  return { premium: quotePremium(step.items, customer, isFollowUp) };
193	};
194	
195	const handleClaim = (step: ClaimStep, policies: Policy[]): ClaimResult =>
196	  processClaim(policies[step.policy], step.incident);
197	
198	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
199	  const policies: Policy[] = [];
200	  const results: StepResult[] = scenario.steps.map((step) =>
201	    step.op === "quote"
202	      ? handleQuote(step, scenario.customer, policies)
203	      : handleClaim(step, policies),
204	  );
205	  return { results };
206	};
